window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c16-fire-sprinkler"] = window.COURSE_LANG["c16-fire-sprinkler"] || {};
window.COURSE_LANG["c16-fire-sprinkler"]["es"] = [
  {"id":1,"q":"En un sistema de rociadores de tubería húmeda, la tubería sobre la válvula de alarma normalmente está llena de:","opts":["Agua a presión","Aire a presión","Nitrógeno","Espuma anticongelante"],"re":"Un sistema de tubería húmeda mantiene la tubería siempre llena de agua a presión, de modo que el agua descarga en cuanto se abre un rociador."},
  {"id":2,"q":"Un sistema de tubería seca se usa principalmente donde:","opts":["Se requiere una entrega de agua muy rápida","El área puede congelarse y un sistema húmedo se reventaría","El techo es muy bajo","Solo se desea detección de humo"],"re":"Los sistemas de tubería seca contienen aire a presión en lugar de agua para que la tubería no se congele en espacios sin calefacción; el agua entra solo cuando un rociador activa la válvula seca."},
  {"id":3,"q":"En un sistema de tubería seca, el suministro de agua se retiene mediante:","opts":["Solo un solenoide","El peso de la columna de agua","Presión de aire o nitrógeno que mantiene cerrada la válvula de tubería seca","Solo la gravedad"],"re":"El aire o nitrógeno a presión sobre la clapeta de la válvula de tubería seca retiene el suministro de agua hasta que se abre un rociador y se libera el aire."},
  {"id":4,"q":"En un sistema de diluvio, los rociadores (o boquillas) están:","opts":["Cerrados con ampollas de vidrio","Cerrados con eslabones fusibles","Tapados hasta su instalación","Todos abiertos, con el agua retenida por una válvula de diluvio"],"re":"Los sistemas de diluvio usan cabezas abiertas; cuando un sistema de detección independiente activa la válvula de diluvio, el agua sale por todas las cabezas a la vez."},
  {"id":5,"q":"Un sistema de preacción de doble enclavamiento admite agua solo después de que:","opts":["Se abre un rociador, sin necesidad de detector","Opera un detector, sin necesidad de rociador","Operan tanto un dispositivo de detección COMO un rociador","Una llave manual y una llamada telefónica"],"re":"Un sistema de preacción de doble enclavamiento requiere que operen tanto un dispositivo de detección como un rociador antes de admitir agua, lo que evita descargas accidentales."},
  {"id":6,"q":"Un sistema de diluvio es más apropiado para:","opts":["Un área de alto riesgo, como un hangar de aviones que necesita un flujo de agua intenso y simultáneo","Una oficina pequeña","Un pasillo típico de hotel","Solo un ático sin calefacción"],"re":"Los sistemas de diluvio aplican agua rápidamente sobre toda un área y se adaptan a espacios de alto riesgo como hangares y ciertas áreas con líquidos inflamables."},
  {"id":7,"q":"En comparación con un sistema de tubería húmeda, un sistema de tubería seca entrega agua a un rociador abierto:","opts":["Más rápido","En el mismo instante","Solo cuando se activa manualmente","Con un retraso"],"re":"Como el aire debe purgarse antes de que el agua avance por la tubería, los sistemas de tubería seca tienen un retraso inherente en la entrega de agua."},
  {"id":8,"q":"La temperatura más baja a la que un sistema de tubería húmeda puede usarse normalmente sin protección contra congelación es de aproximadamente:","opts":["40°F (4°C)","0°F (-18°C)","20°F (-7°C)","70°F (21°C)"],"re":"Un sistema de tubería húmeda solo debe dar servicio a espacios que se mantengan de forma confiable a 40°F (4°C) o más; las áreas más frías requieren tubería seca, preacción o anticongelante."},
  {"id":9,"q":"Un sistema de preacción de enclavamiento simple admite agua en la tubería cuando:","opts":["Opera un dispositivo de detección","Se funden dos rociadores","Se abre el drenaje principal","Arranca la bomba contra incendios"],"re":"En un sistema de preacción de enclavamiento simple, la operación del dispositivo de detección abre la válvula de preacción y llena la tubería antes de que se abra cualquier rociador."},

  {"id":10,"q":"Una columna de agua ejerce una presión de aproximadamente:","opts":["0.433 psi por pie de altura","1.0 psi por pie de altura","5.0 psi por pie de altura","10 psi por pie de altura"],"re":"El agua ejerce alrededor de 0.433 psi por pie vertical; de forma equivalente, se necesitan unos 2.31 pies de agua para generar 1 psi."},
  {"id":11,"q":"A medida que el agua sube a un piso más alto, el cambio de elevación hace que la presión:","opts":["Aumente","Se mantenga exactamente igual","Se duplique por piso","Disminuya"],"re":"La elevación creciente añade carga que el sistema debe vencer, así que la presión disminuye unos 0.433 psi por cada pie de subida."},
  {"id":12,"q":"La presión leída en un manómetro del sistema sin flujo de agua se llama:","opts":["Presión de velocidad","Presión estática","Presión residual","Presión de fricción"],"re":"La presión estática es la lectura sin flujo; la presión residual es la que queda mientras el agua fluye."},
  {"id":13,"q":"La conexión para el departamento de bomberos (FDC) se proporciona para que los bomberos puedan:","opts":["Drenar el sistema","Apagar la alarma","Complementar el suministro de agua del sistema con líneas de manguera","Probar los detectores de humo"],"re":"La FDC (conexión siamesa) permite al departamento de bomberos bombear agua y presión adicionales al sistema de rociadores o de tubería vertical."},
  {"id":14,"q":"La pérdida de presión causada por el roce del agua contra el interior de la tubería se llama:","opts":["Pérdida por fricción","Pérdida por elevación","Pérdida estática","Pérdida por sobrepresión"],"re":"La pérdida por fricción es la caída de presión por el agua que se mueve contra la pared de la tubería; crece con el caudal y con tubería más pequeña o rugosa."},
  {"id":15,"q":"Se requiere una válvula de retención (check) en la tubería de la FDC para que:","opts":["El sistema se drene más rápido","La alarma suene más fuerte","La bomba funcione continuamente","El agua de la ciudad o del sistema no pueda salir de vuelta por la FDC"],"re":"La válvula de retención de la FDC evita que el agua del sistema o del suministro salga por las entradas y dirige el agua del departamento de bomberos hacia el sistema."},
  {"id":16,"q":"En una prueba de flujo del agua de la ciudad, la diferencia entre la presión estática y la residual revela principalmente:","opts":["El color de la tubería","La clasificación de temperatura del rociador","Cuánto se debilita el suministro cuando fluye agua","La cantidad de cabezas"],"re":"Comparar la presión estática con la residual (en flujo) muestra cuánto cae el suministro de agua bajo demanda, un dato clave para el diseño hidráulico."},
  {"id":17,"q":"¿Qué dispositivo evita que el agua del sistema de rociadores contamine el suministro potable de la ciudad?","opts":["Un preventor de reflujo (backflow)","Una cámara de retardo","Un acelerador","Un gong hidráulico"],"re":"Un preventor de reflujo (a menudo un conjunto de doble retención) impide que el agua del sistema, posiblemente contaminada, regrese a la red pública de agua potable."},
  {"id":18,"q":"En un sistema calculado hidráulicamente, el diseño comienza en:","opts":["El rociador más cercano al montante","La tubería más grande","Solo la bomba contra incendios","El área de diseño más remota (hidráulicamente menos favorable)"],"re":"Los cálculos comienzan en el área de diseño hidráulicamente más remota y avanzan hacia el suministro, para que el punto más desfavorable reciba la densidad requerida."},

  {"id":19,"q":"El arriostramiento sísmico (sway bracing) en la tubería de rociadores se instala principalmente para:","opts":["Soportar el peso estático de la tubería","Acelerar la entrega de agua","Reducir la pérdida por fricción","Resistir el movimiento horizontal durante un sismo"],"re":"Los soportes (hangers) cargan el peso vertical (por gravedad); el arriostramiento sísmico resiste las fuerzas laterales y longitudinales que un sismo ejerce sobre la tubería."},
  {"id":20,"q":"En la parte superior de un montante de rociadores, el arriostre sísmico recomendado es un:","opts":["Arriostre lateral simple","Soporte corto de varilla","Arriostre de cuatro vías","Solo una bajada flexible"],"re":"Un arriostre de cuatro vías en la parte superior del montante resiste el movimiento en todas las direcciones horizontales donde el montante se une a las tuberías de alimentación."},
  {"id":21,"q":"En edificios de varios pisos, los acoplamientos flexibles se añaden principalmente donde la tubería:","opts":["Cambia de diámetro","Pasa entre pisos para que pueda moverse sin romperse","Está pintada de rojo","Se conecta a una cabeza colgante"],"re":"Los acoplamientos flexibles cerca de las penetraciones entre pisos permiten que la tubería se flexione con el movimiento del edificio durante un sismo en vez de agrietarse."},
  {"id":22,"q":"Los arriostres laterales de oscilación resisten el movimiento que es:","opts":["A lo largo del tramo de tubería","Perpendicular (de lado a lado) al tramo de tubería","Solo recto hacia abajo","Solo rotacional"],"re":"Los arriostres laterales resisten el movimiento de lado a lado a través de la tubería, mientras que los longitudinales resisten el movimiento a lo largo de ella."},
  {"id":23,"q":"El propósito principal de los soportes (hangers) de tubería es:","opts":["Proporcionar el arriostramiento sísmico","Drenar el sistema","Soportar el peso de la tubería llena de agua","Sostener los embellecedores del rociador"],"re":"Los soportes cargan el peso muerto de la tubería llena de agua; el arriostramiento es una provisión aparte para las fuerzas sísmicas."},
  {"id":24,"q":"Los arriostres longitudinales de oscilación resisten el movimiento:","opts":["De lado a lado a través de la tubería","Solo en la cabeza del rociador","Solo en la FDC","En la dirección de la longitud de la tubería"],"re":"Los arriostres longitudinales resisten las fuerzas que actúan a lo largo (paralelas) del tramo de tubería; se espacian más que los laterales."},
  {"id":25,"q":"Un método común de unión de tubería de acero que usa un extremo ranurado y un acoplamiento se llama:","opts":["Una conexión abocardada (flare)","Una unión de compresión","Una junta de campana a presión","Un acoplamiento ranurado (mecánico)"],"re":"Los acoplamientos mecánicos ranurados unen extremos de tubería ranurada (rolada o cortada) y se usan mucho en sistemas de rociadores por su rapidez y cierta flexibilidad."},
  {"id":26,"q":"La restricción sísmica de una línea ramal se requiere al menos en:","opts":["La mitad de cada tramo","El extremo de la línea","La bomba contra incendios","Solo la FDC"],"re":"Restringir el extremo de una línea ramal (y a lo largo de ella según el tamaño de la tubería) evita que el extremo sin arriostrar latiguee durante el movimiento sísmico."},
  {"id":27,"q":"La tubería de acero roscada para rociadores se sella en las juntas usando:","opts":["Soldadura","Compuesto para juntas de tubería o cinta selladora de roscas","Pintura epóxica","Solo un empaque de hule"],"re":"Las roscas cónicas de tubería se sellan con compuesto para juntas o cinta de PTFE adecuada para la aplicación homologada."},

  {"id":28,"q":"Un rociador montante (upright) se identifica porque su deflector está colocado:","opts":["Debajo del orificio","Encima del orificio, con la cabeza apuntando hacia arriba","Dentro del orificio","Al ras del techo"],"re":"Una cabeza montante se sitúa sobre la línea ramal y lanza el agua hacia arriba contra un deflector diseñado para esa orientación; una colgante (pendent) cuelga hacia abajo."},
  {"id":29,"q":"Para cabezas de aspersión estándar en una ocupación de riesgo ligero, el área de piso máxima que un rociador puede proteger es de aproximadamente:","opts":["225 pies²","100 pies²","150 pies²","400 pies²"],"re":"En espacios de riesgo ligero sin obstrucciones, un rociador montante o colgante de aspersión estándar cubre hasta unos 225 pies²."},
  {"id":30,"q":"Para cabezas de aspersión estándar en riesgo ligero, el espaciamiento máximo entre rociadores es de aproximadamente:","opts":["8 pies","12 pies","15 pies","20 pies"],"re":"Los rociadores de aspersión estándar de riesgo ligero se espacian no más de unos 15 pies a lo largo y entre las líneas ramales."},
  {"id":31,"q":"La distancia mínima permitida entre dos rociadores de aspersión estándar es generalmente:","opts":["6 pies","2 pies","4 pies","10 pies"],"re":"Los rociadores normalmente se colocan no más cerca de 6 pies entre centros para que la descarga de una cabeza no enfríe ni retrase a la vecina."},
  {"id":32,"q":"Un rociador con ampolla de vidrio naranja o roja está clasificado para el rango de temperatura ordinaria de aproximadamente:","opts":["135°F a 170°F","200°F a 250°F","325°F a 375°F","Menos de 100°F"],"re":"Los rociadores de temperatura ordinaria (unos 135°F–170°F) usan una ampolla de vidrio naranja o roja y se adaptan a espacios ocupados normales."},
  {"id":33,"q":"En un rociador de ampolla de vidrio, la cabeza se activa cuando:","opts":["Un detector envía una señal","Arranca la bomba contra incendios","El líquido de la ampolla se calienta, se expande y la rompe","Alguien gira una válvula"],"re":"El calor expande el líquido de la ampolla de vidrio hasta que estalla, liberando el tapón y permitiendo que el agua salga de esa sola cabeza."},
  {"id":34,"q":"Generalmente se elige un rociador de temperatura más alta cuando la cabeza está:","opts":["En una cámara frigorífica","En un sótano","Bajo el nivel del suelo","Cerca de una fuente de calor, como un calefactor de unidad o un tragaluz"],"re":"Las cabezas de mayor temperatura se usan cerca de fuentes de calor para que el calor ambiente normal no cause una activación no deseada (accidental)."},
  {"id":35,"q":"Un rociador colgante (pendent) normalmente se instala:","opts":["Apuntando hacia arriba desde una línea ramal expuesta","Colgando hacia abajo bajo un techo terminado","Horizontalmente desde una pared","Dentro del montante"],"re":"Una cabeza colgante cuelga bajo el techo para que la tubería pueda ocultarse arriba; una montante apunta hacia arriba en tubería expuesta."},
  {"id":36,"q":"Un rociador que sobresale horizontalmente de una pared en lugar de hacerlo desde el techo es un:","opts":["Rociador montante","Rociador colgante","Rociador de pared (sidewall)","Colgante oculto"],"re":"Un rociador de pared descarga agua hacia afuera y a través de la sala desde una pared, útil donde la tubería en el techo no es práctica."},

  {"id":37,"q":"Un sistema de tubería vertical (standpipe) Clase I proporciona conexiones de manguera de tamaño:","opts":["1 pulgada","1½ pulgada","2½ pulgadas","4 pulgadas"],"re":"Los standpipes Clase I suministran conexiones de 2½ pulgadas destinadas al uso del departamento de bomberos; la Clase II provee estaciones de manguera de 1½ pulgada."},
  {"id":38,"q":"Un sistema de tubería vertical Clase II está destinado principalmente al uso de:","opts":["El departamento de bomberos con manguera grande","Robots de mantenimiento","Nadie — es decorativo","Ocupantes capacitados o primeros respondedores con manguera de 1½ pulgada"],"re":"Los sistemas Clase II proveen estaciones de manguera de 1½ pulgada para uso de personal capacitado en las etapas iniciales de un incendio."},
  {"id":39,"q":"Una válvula OS&Y indica si está abierta o cerrada por la posición de su:","opts":["Color de la manija","Vástago roscado que sube o baja","Manómetro","Tapón de drenaje"],"re":"En una válvula de vástago y horquilla exteriores (OS&Y), el vástago sube al abrir y baja al cerrar, dando una indicación visual clara."},
  {"id":40,"q":"Una válvula de control principal en un sistema de rociadores debe ser:","opts":["Oculta a la vista","Una válvula indicadora para que su posición de abierto/cerrado sea visible","Pintada de verde","Dejada sin supervisión"],"re":"Las válvulas de control principales deben ser de tipo indicador (OS&Y, mariposa con indicador o PIV) y normalmente se supervisan para que permanezcan abiertas."},
  {"id":41,"q":"Una bomba jockey (de mantenimiento de presión) se usa para:","opts":["Mantener la presión para que la bomba principal no arranque por fugas pequeñas","Proporcionar todo el flujo contra incendios","Drenar el sistema","Probar la alarma"],"re":"La pequeña bomba jockey compensa pérdidas menores de presión, evitando arranques innecesarios de la bomba principal; no suministra el caudal de combate de incendios."},
  {"id":42,"q":"La presión de descarga sin flujo (de cierre) de una bomba contra incendios se conoce como su:","opts":["Presión estática de la ciudad","Presión residual","Capacidad nominal","Presión de churn (sin flujo)"],"re":"La presión de churn (cierre) es la presión de descarga sin flujo de agua; la capacidad y la presión nominales se definen al caudal de diseño."},
  {"id":43,"q":"En un sistema de tubería húmeda, el dispositivo que ayuda a evitar una falsa alarma por una breve sobrepresión es la:","opts":["Cámara de retardo","Acelerador","Válvula de diluvio","Bomba jockey"],"re":"La cámara de retardo retiene brevemente el agua de una sobrepresión momentánea para que un pico corto de presión no dispare una falsa alarma de flujo de agua."},
  {"id":44,"q":"Un gong hidráulico (water motor gong) es una alarma que está:","opts":["Alimentada por batería","Accionada por el motor de la bomba contra incendios","Activada solo por humo","Accionada por el agua que fluye, sin necesidad de electricidad"],"re":"El gong hidráulico es una campana mecánica accionada por agua en el exterior del montante que suena cuando fluye agua, sin necesidad de energía eléctrica."},

  {"id":45,"q":"La NFPA 13 es la norma que cubre principalmente:","opts":["La inspección y prueba de sistemas existentes","La instalación de sistemas de rociadores","Los extintores portátiles","El cableado de alarmas contra incendios"],"re":"La NFPA 13 rige el diseño y la instalación de sistemas de rociadores; la NFPA 25 cubre su inspección, prueba y mantenimiento continuos."},
  {"id":46,"q":"Un sistema de rociadores nuevo se prueba hidrostáticamente para su aceptación a no menos de:","opts":["50 psi durante 1 hora","100 psi durante 30 minutos","200 psi durante 2 horas","500 psi durante 4 horas"],"re":"La tubería nueva o modificada se prueba hidrostáticamente a 200 psi (o 50 psi por encima de la presión de trabajo si esta supera 150 psi) durante 2 horas sin fugas."},
  {"id":47,"q":"Las categorías de riesgo por ocupación de la NFPA 13, de menor a mayor, son:","opts":["Menor, Mayor, Severo","Clase A, B, C","Riesgo ligero, ordinario, extra","Verde, Amarillo, Rojo"],"re":"La NFPA 13 clasifica los espacios como riesgo ligero, ordinario (Grupos 1–2) o extra (Grupos 1–2), donde las clases más altas requieren mayor densidad de agua."},
  {"id":48,"q":"Según la NFPA 25, la prueba de rutina que verifica el suministro de agua abriendo por completo un drenaje del montante es la:","opts":["Prueba hidrostática","Prueba de disparo (trip)","Prueba de lavado","Prueba de drenaje principal"],"re":"La prueba de drenaje principal abre el drenaje principal del montante y compara la presión estática con la residual para confirmar que el suministro no se ha deteriorado."},
  {"id":49,"q":"Un sistema de tubería seca debe diseñarse para que el agua llegue a la conexión de prueba del inspector más remota en aproximadamente:","opts":["10 segundos","60 segundos","5 minutos","15 minutos"],"re":"La NFPA 13 limita el retraso de entrega de agua en sistemas secos (puede añadirse un dispositivo de apertura rápida) para que el agua llegue al punto de prueba remoto en unos 60 segundos."},
  {"id":50,"q":"Las clasificaciones de riesgo más altas de la NFPA 13 generalmente requieren una:","opts":["Mayor densidad de aplicación de agua (gpm por pie²)","Menor densidad de agua","Solo tubería más larga","Bomba contra incendios más pequeña"],"re":"Una mayor carga combustible implica incendios más rápidos y calientes, así que las áreas de riesgo extra necesitan densidades de diseño más altas que las de riesgo ordinario o ligero."}
];
